parameters.text:
Please summarize the following TechCrunch news article in exactly two engaging, professional sentences. Focus on the core value proposition, key facts, or important takeaways. Provide ONLY the plain text summary, and do NOT include the article title, markdown formatting (no bold/italics), or HTML tags.

Title: {{ $json.title }}
Description: {{ $json.contentSnippet || $json.content || '' }}

parameters.jsCode:
const rssItems = $('Limit').all();
const aiItems = $input.all();

let emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body {
      font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      background-color: #f8fafc;
      color: #1e293b;
      margin: 0;
      padding: 0;
    }
    .container {
      max-width: 600px;
      margin: 40px auto;
      background: #ffffff;
      border-radius: 16px;
      box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -4px rgba(0, 0, 0, 0.05);
      border: 1px solid #e2e8f0;
      overflow: hidden;
    }
    .header {
      background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
      color: #ffffff;
      padding: 36px 24px;
      text-align: center;
      border-bottom: 4px solid #0284c7;
    }
    .header h1 {
      margin: 0;
      font-size: 26px;
      font-weight: 800;
      letter-spacing: -0.03em;
    }
    .header p {
      margin: 8px 0 0 0;
      font-size: 14px;
      color: #94a3b8;
      font-weight: 500;
    }
    .content {
      padding: 32px 24px;
    }
    .article-card {
      background: #ffffff;
      border-radius: 12px;
      padding: 20px;
      margin-bottom: 24px;
      border: 1px solid #f1f5f9;
      box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.02);
    }
    .article-title {
      font-size: 18px;
      font-weight: 700;
      margin: 0 0 8px 0;
      line-height: 1.4;
      letter-spacing: -0.01em;
    }
    .article-title a {
      color: #0284c7;
      text-decoration: none;
    }
    .article-title a:hover {
      color: #0369a1;
      text-decoration: underline;
    }
    .article-meta {
      font-size: 12px;
      color: #64748b;
      margin-bottom: 12px;
      font-weight: 600;
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }
    .article-summary {
      font-size: 14px;
      line-height: 1.6;
      color: #334155;
      margin: 0;
    }
    .footer {
      background-color: #f8fafc;
      padding: 24px;
      text-align: center;
      font-size: 12px;
      color: #64748b;
      border-top: 1px solid #e2e8f0;
      line-height: 1.5;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>⚡ TechCrunch AI Digest</h1>
      <p>Your curated, AI-summarized tech news briefing</p>
    </div>
    <div class="content">
`;

aiItems.forEach((item, index) => {
  const rss = rssItems[index] ? rssItems[index].json : {};
  const title = rss.title || 'Untitled Article';
  const link = rss.link || '#';
  const pubDate = rss.pubDate ? new Date(rss.pubDate).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  }) : 'Recently';
  const summary = item.json.output || 'Summary not available.';

  emailHtml += `
    <div class="article-card">
      <div class="article-meta">Published: ${pubDate}</div>
      <h2 class="article-title"><a href="${link}" target="_blank">${title}</a></h2>
      <p class="article-summary">${summary}</p>
    </div>
  `;
});

emailHtml += `
    </div>
    <div class="footer">
      <p>This automated briefing was generated by <strong>n8n</strong> using advanced AI summarization.</p>
      <p>&copy; ${new Date().getFullYear()} TechCrunch AI Digest. All rights reserved.</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    subject: `⚡ TechCrunch AI Digest: ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`,
    htmlBody: emailHtml
  }
}];
